// Rise 6.0 - KillAura/ESP mob tracking from S0F:
@EventLink()
public final Listener<PacketReceiveEvent> onPacketReceive = event -> {
    if (event.getPacket() instanceof S0FPacketSpawnMob) {
        S0FPacketSpawnMob s0f = (S0FPacketSpawnMob) event.getPacket();
        int entityId = s0f.getEntityID();
        int mobType = s0f.getEntityType();

        // Add to KillAura target list based on type filter
        if (shouldTarget(mobType)) {
            if (!killAuraTargets.contains(entityId)) {
                killAuraTargets.add(entityId);
            }
        }

        // Add to ESP render list
        if (shouldRender(mobType)) {
            espTargets.put(entityId, mobType);
        }
    }
};

private boolean shouldTarget(int mobType) {
    if (mobFilter.equals("Hostile")) {
        // Hostile mob types: 50-68 range
        return mobType >= 50 && mobType <= 68;
    }
    if (mobFilter.equals("Passive")) {
        // Passive mob types: 90-101 range
        return mobType >= 90 && mobType <= 101;
    }
    if (mobFilter.equals("All")) {
        return true;
    }
    return false;
}

